'use client';

import React, { useState, useMemo } from 'react';
import { motion } from 'framer-motion';
import { MOCK_PARTNER_NGOS, MOCK_PROJECTS, MOCK_DONATIONS, SDG_INFO } from '@/data/mockData';
import { findMatches } from '@/services/matching';
import AnimatedCounter from '@/components/ui/AnimatedCounter';

const fadeIn = (d: number) => ({
    initial: { opacity: 0, y: 20 },
    animate: { opacity: 1, y: 0 },
    transition: { duration: 0.5, delay: d },
});

export default function CorporateDashboard() {
    const [sdgFilter, setSdgFilter] = useState<number | null>(null);
    const [stateFilter, setStateFilter] = useState('');
    const corporateSDGs = [3, 4, 6, 7, 11];

    const totalCSRSpend = 4500000;
    const projectsFunded = 4;
    const sdgsSupported = 8;

    const matches = useMemo(() => {
        return findMatches(MOCK_PARTNER_NGOS, {
            sdg_focus: sdgFilter ? [sdgFilter] : undefined,
            state: stateFilter || undefined,
        }, corporateSDGs);
    }, [sdgFilter, stateFilter]);

    const handleGenerateReport = () => {
        // Create a simple CSV-style report
        const reportContent = [
            'SDG NEXUS - CSR COMPLIANCE REPORT',
            `Generated: ${new Date().toLocaleDateString()}`,
            `Organization: TechServe India CSR`,
            '',
            'SUMMARY',
            `Total CSR Spend: ₹${totalCSRSpend.toLocaleString()}`,
            `Projects Funded: ${projectsFunded}`,
            `SDGs Supported: ${sdgsSupported}`,
            `Total Beneficiaries: 80,000+`,
            '',
            'PROJECTS',
            ...MOCK_PROJECTS.slice(0, 4).map(p =>
                `- ${p.title} | Budget: ₹${p.budget.toLocaleString()} | SDGs: ${p.sdg_tags.join(', ')} | Beneficiaries: ${p.beneficiary_count.toLocaleString()}`
            ),
        ].join('\n');

        const blob = new Blob([reportContent], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'SDG_Nexus_CSR_Report.txt';
        a.click();
        URL.revokeObjectURL(url);
    };

    return (
        <div className="space-y-6">
            <motion.div {...fadeIn(0)} className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-white">CSR Dashboard</h1>
                    <p className="text-sm text-gray-500 mt-1">TechServe India CSR • Corporate Dashboard</p>
                </div>
                <button onClick={handleGenerateReport} className="btn-neon text-sm">
                    📄 Generate CSR Report
                </button>
            </motion.div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {[
                    { label: 'Total CSR Spend', value: 45, icon: '💰', color: '#06b6d4', prefix: '₹', suffix: ' Lakh' },
                    { label: 'Projects Funded', value: projectsFunded, icon: '📁', color: '#10b981' },
                    { label: 'SDGs Impacted', value: sdgsSupported, icon: '🎯', color: '#8b5cf6' },
                    { label: 'Lives Impacted', value: 80000, icon: '👥', color: '#f59e0b' },
                ].map((stat, i) => (
                    <motion.div key={i} {...fadeIn(0.05 * (i + 1))} className="glass-card p-5">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-2xl">{stat.icon}</span>
                            <span className="text-xs px-2 py-1 rounded-lg" style={{ background: stat.color + '15', color: stat.color }}>{stat.label}</span>
                        </div>
                        <div className="text-3xl font-bold text-white">
                            <AnimatedCounter target={stat.value} prefix={stat.prefix} suffix={stat.suffix} />
                        </div>
                    </motion.div>
                ))}
            </div>

            {/* Smart Matching */}
            <motion.div {...fadeIn(0.3)} className="glass-card p-6">
                <div className="flex items-center justify-between mb-4">
                    <div>
                        <h2 className="text-lg font-semibold text-white">🤝 Smart Partner Matching</h2>
                        <p className="text-xs text-gray-500 mt-1">AI-powered NGO recommendations based on your CSR focus areas</p>
                    </div>
                </div>

                {/* Filters */}
                <div className="flex flex-wrap gap-3 mb-5">
                    <select value={sdgFilter || ''} onChange={e => setSdgFilter(e.target.value ? parseInt(e.target.value) : null)}
                        className="input-dark w-auto text-sm py-2">
                        <option value="">All SDGs</option>
                        {SDG_INFO.map(s => <option key={s.id} value={s.id}>SDG {s.id}: {s.name}</option>)}
                    </select>
                    <input type="text" value={stateFilter} onChange={e => setStateFilter(e.target.value)}
                        className="input-dark w-auto text-sm py-2" placeholder="Filter by state..." />
                </div>

                {/* Partner Cards */}
                <div className="grid md:grid-cols-2 gap-4">
                    {matches.map((match, i) => (
                        <motion.div key={match.ngo.id}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: i * 0.08 }}
                            className="p-4 rounded-xl transition-all hover:bg-white/5"
                            style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.06)' }}
                        >
                            <div className="flex items-center justify-between mb-3">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-xl flex items-center justify-center text-lg"
                                        style={{ background: 'linear-gradient(135deg, #06b6d4, #8b5cf6)' }}>
                                        {match.ngo.name.charAt(0)}
                                    </div>
                                    <div>
                                        <p className="text-sm font-semibold text-white">{match.ngo.name}</p>
                                        <p className="text-xs text-gray-500">{match.ngo.location.state}</p>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <div className="text-lg font-bold text-cyan-400">{match.match_score}%</div>
                                    <div className="text-[10px] text-gray-500">Match</div>
                                </div>
                            </div>

                            <div className="flex flex-wrap gap-1.5 mb-3">
                                {match.ngo.sdg_focus.map(s => (
                                    <span key={s} className={`sdg-${s} text-[10px] px-2 py-0.5 rounded-md`}>SDG {s}</span>
                                ))}
                            </div>

                            <div className="grid grid-cols-3 gap-2 text-center">
                                <div className="p-2 rounded-lg" style={{ background: 'rgba(255,255,255,0.03)' }}>
                                    <p className="text-xs font-bold text-white">{match.ngo.impact_score}</p>
                                    <p className="text-[10px] text-gray-500">Impact</p>
                                </div>
                                <div className="p-2 rounded-lg" style={{ background: 'rgba(255,255,255,0.03)' }}>
                                    <p className="text-xs font-bold text-white">₹{(match.ngo.funding_need / 100000).toFixed(0)}L</p>
                                    <p className="text-[10px] text-gray-500">Need</p>
                                </div>
                                <div className="p-2 rounded-lg" style={{ background: 'rgba(255,255,255,0.03)' }}>
                                    <p className="text-xs font-bold text-white">{match.ngo.beneficiaries.toLocaleString()}</p>
                                    <p className="text-[10px] text-gray-500">Reach</p>
                                </div>
                            </div>

                            {match.reasons.length > 0 && (
                                <div className="mt-3 text-xs text-gray-400">
                                    {match.reasons.map((r, ri) => (
                                        <span key={ri} className="inline-block mr-2">✓ {r}</span>
                                    ))}
                                </div>
                            )}

                            {match.ngo.verified && (
                                <div className="mt-2 flex items-center gap-1">
                                    <span className="text-[10px] px-2 py-0.5 rounded-md" style={{ background: 'rgba(16,185,129,0.1)', color: '#10b981' }}>✓ Verified</span>
                                </div>
                            )}
                        </motion.div>
                    ))}
                </div>
            </motion.div>
        </div>
    );
}
